import{_ as a,o as s,c as e,S as o}from"./chunks/framework.7245853a.js";const F=JSON.parse('{"title":"🫠 SEO 通用优化方案","description":"","frontmatter":{"sticky":3,"title":"🫠 SEO 通用优化方案","tag":["优化","SEO","前端"],"top":1,"sidebar":true},"headers":[],"relativePath":"前端/优化/SEO 通用优化方案.md","filePath":"前端/优化/SEO 通用优化方案.md","lastUpdated":null}'),t={name:"前端/优化/SEO 通用优化方案.md"},l=o('<h1 id="内容方面优化" tabindex="-1"><strong>内容方面优化</strong> <a class="header-anchor" href="#内容方面优化" aria-label="Permalink to &quot;**内容方面优化**&quot;">​</a></h1><h2 id="_1-增加-mate-descripition" tabindex="-1">1.<strong>增加 Mate Descripition</strong> <a class="header-anchor" href="#_1-增加-mate-descripition" aria-label="Permalink to &quot;1.**增加 Mate Descripition**&quot;">​</a></h2><p>每个页面</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">meta</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">description</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">content</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">xxxxxxxx</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><p>填写页面的介绍，160单词~170单词，可参考竞品</p><h2 id="_2-纯文本-a-link-文案可读性" tabindex="-1">2.<strong>纯文本 A Link 文案可读性</strong> <a class="header-anchor" href="#_2-纯文本-a-link-文案可读性" aria-label="Permalink to &quot;2.**纯文本 A Link 文案可读性**&quot;">​</a></h2><p>A Link 跳转的文本具有可读性，比如“More”按钮可以将其改成“More Apps”更直观</p><h2 id="_3-图片增加-alt-属性" tabindex="-1">3.<strong>图片增加 Alt 属性</strong> <a class="header-anchor" href="#_3-图片增加-alt-属性" aria-label="Permalink to &quot;3.**图片增加 Alt 属性**&quot;">​</a></h2><p>给页面中每张图片增加有意义的alt属性，可以是对图片的描述，图片表示的功能。</p><h2 id="_4-设置网站title" tabindex="-1">4.<strong>设置网站title</strong> <a class="header-anchor" href="#_4-设置网站title" aria-label="Permalink to &quot;4.**设置网站title**&quot;">​</a></h2><p>每个页面</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">title</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;">XXXXXX</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">title</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><p>填写页面的标题，50单词~100单词，可参考竞品</p><h2 id="_5-设置网站icon" tabindex="-1">5.<strong>设置网站Icon</strong> <a class="header-anchor" href="#_5-设置网站icon" aria-label="Permalink to &quot;5.**设置网站Icon**&quot;">​</a></h2><p>每个页面设置的lcon都应该相同，只对域名的首页起作用。</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">link</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">rel</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">icon</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">xxxx</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h2 id="_6-结构化数据-不同产品结构化数据内容不同" tabindex="-1">6.<strong>结构化数据，不同产品结构化数据内容不同</strong> <a class="header-anchor" href="#_6-结构化数据-不同产品结构化数据内容不同" aria-label="Permalink to &quot;6.**结构化数据，不同产品结构化数据内容不同**&quot;">​</a></h2><h1 id="通用结构化数据" tabindex="-1"><strong>通用结构化数据</strong> <a class="header-anchor" href="#通用结构化数据" aria-label="Permalink to &quot;**通用结构化数据**&quot;">​</a></h1><h2 id="_1-设置网站logo" tabindex="-1">1.<strong>设置网站Logo</strong> <a class="header-anchor" href="#_1-设置网站logo" aria-label="Permalink to &quot;1.**设置网站Logo**&quot;">​</a></h2><p>只需要在首页上设置</p><p>网页header增加JSON-LD，参考<a href="https://developers.google.com/search/docs/appearance/structured-data/logo?hl=zh-cn#example" target="_blank" rel="noreferrer">https://developers.google.com/search/docs/appearance/structured-data/logo?hl=zh-cn#example</a></p><p>Logo Icon要求：</p><p>大小至少112x112</p><p>格式的图片： BMP、GIF、JPEG、PNG、WebP 和 SVG</p><p>示例</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">application/ld+json</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h2 id="_2-设置网站名称" tabindex="-1">2.<strong>设置网站名称</strong> <a class="header-anchor" href="#_2-设置网站名称" aria-label="Permalink to &quot;2.**设置网站名称**&quot;">​</a></h2><p>只需要在首页上设置</p><p>网页header增加JSON-LD，参考<a href="https://developers.google.com/search/docs/appearance/site-names?hl=zh-cn#how-to-add-structured-data" target="_blank" rel="noreferrer">https://developers.google.com/search/docs/appearance/site-names?hl=zh-cn#how-to-add-structured-data</a></p><p>名称描述尽可能50个字符以上，但不能太长。可参考竞品重新组织语言。</p><p>示例</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">application/ld+json</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h2 id="_3-设置网站更新时间" tabindex="-1">3.<strong>设置网站更新时间</strong> <a class="header-anchor" href="#_3-设置网站更新时间" aria-label="Permalink to &quot;3.**设置网站更新时间**&quot;">​</a></h2><p>可对有定期更新内容的关键页面进行设置</p><p>网页header增加JSON-LD，参考<a href="https://developers.google.com/search/docs/appearance/publication-dates?hl=zh-cn%EF%BC%8C%E5%BB%BA%E8%AE%AE%E6%B7%BB%E5%8A%A0%5BCreativeWork%5D(https://schema.org/CreativeWork)%E7%9A%84%E5%AD%90%E7%B1%BB%E5%9E%8B%EF%BC%88%E4%BE%8B%E5%A6%82%5BArticle%5D(https://developers.google.com/search/docs/appearance/structured-data/article?hl=zh-cn)%E3%80%81%5BBlogPosting%5D(https://schema.org/BlogPosting)%E6%88%96%5BVideoObject%5D(https://developers.google.com/search/docs/appearance/structured-data/video?hl=zh-cn)%EF%BC%89%EF%BC%8C%E5%B9%B6%E6%8C%87%E5%AE%9AdatePublished%E5%92%8C/%E6%88%96dateModified%E5%AD%97%E6%AE%B5" target="_blank" rel="noreferrer">https://developers.google.com/search/docs/appearance/publication-dates?hl=zh-cn，建议添加[CreativeWork](https://schema.org/CreativeWork)的子类型（例如[Article](https://developers.google.com/search/docs/appearance/structured-data/article?hl=zh-cn)、[BlogPosting](https://schema.org/BlogPosting)或[VideoObject](https://developers.google.com/search/docs/appearance/structured-data/video?hl=zh-cn)），并指定datePublished和/或dateModified字段</a></p><p>示例</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">application/ld+json</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">@context</span><span style="color:#89DDFF;">&quot;</span><span style="color:#BABED8;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">https://schema.org</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,&lt;/</span><span style="color:#BABED8;">script</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h2 id="_4-设置面包屑路径" tabindex="-1">4.<strong>设置面包屑路径</strong> <a class="header-anchor" href="#_4-设置面包屑路径" aria-label="Permalink to &quot;4.**设置面包屑路径**&quot;">​</a></h2><p>针对页面跳转路径进行设置</p><p>网页header增加JSON-LD，参考<a href="https://developers.google.com/search/docs/appearance/structured-data/breadcrumb?hl=zh-cn#json-ld" target="_blank" rel="noreferrer">https://developers.google.com/search/docs/appearance/structured-data/breadcrumb?hl=zh-cn#json-ld</a></p><p>参考</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">application/ld+json</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h1 id="其他结构化数据" tabindex="-1"><strong>其他结构化数据</strong> <a class="header-anchor" href="#其他结构化数据" aria-label="Permalink to &quot;**其他结构化数据**&quot;">​</a></h1><p><a href="https://developers.google.com/search/docs/appearance/structured-data/search-gallery?hl=zh-cn" target="_blank" rel="noreferrer">https://developers.google.com/search/docs/appearance/structured-data/search-gallery?hl=zh-cn</a></p><h2 id="link-路径命名规范化" tabindex="-1"><strong>Link 路径命名规范化</strong> <a class="header-anchor" href="#link-路径命名规范化" aria-label="Permalink to &quot;**Link 路径命名规范化**&quot;">​</a></h2><p>用有意义的名称，不要使用数字，单词之间用“-”</p><p>可以采用url channle 方式的技术实现路径的变化，并保持原有路径能访问</p><h2 id="url-归一化" tabindex="-1"><strong>Url 归一化</strong> <a class="header-anchor" href="#url-归一化" aria-label="Permalink to &quot;**Url 归一化**&quot;">​</a></h2><h2 id="控制台没有异常" tabindex="-1"><strong>控制台没有异常</strong> <a class="header-anchor" href="#控制台没有异常" aria-label="Permalink to &quot;**控制台没有异常**&quot;">​</a></h2><h2 id="性能方面优化" tabindex="-1"><strong>性能方面优化</strong> <a class="header-anchor" href="#性能方面优化" aria-label="Permalink to &quot;**性能方面优化**&quot;">​</a></h2><h2 id="cls优化" tabindex="-1"><strong>CLS优化</strong> <a class="header-anchor" href="#cls优化" aria-label="Permalink to &quot;**CLS优化**&quot;">​</a></h2><h2 id="tbt优化" tabindex="-1"><strong>TBT优化</strong> <a class="header-anchor" href="#tbt优化" aria-label="Permalink to &quot;**TBT优化**&quot;">​</a></h2><h2 id="lcp优化" tabindex="-1"><strong>LCP优化</strong> <a class="header-anchor" href="#lcp优化" aria-label="Permalink to &quot;**LCP优化**&quot;">​</a></h2>',53),n=[l];function r(p,c,i,h,d,D){return s(),e("div",null,n)}const u=a(t,[["render",r]]);export{F as __pageData,u as default};
